import{_ as n,c as i,o as s,a1 as t}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"OAuth-Authentifizierung: Erstmalige Anmeldung | Antigravity","description":"Lernen Sie den OAuth 2.0 PKCE-Authentifizierungsprozess kennen und schließen Sie die erstmalige Anmeldung für das Antigravity-Plugin ab. Beinhaltet Starten des lokalen OAuth-Servers, Google-Autorisierung, Abrufen der Project ID und Token-Speicherung.","frontmatter":{"title":"OAuth-Authentifizierung: Erstmalige Anmeldung | Antigravity","sidebarTitle":"Anmeldung in 5 Minuten","subtitle":"OAuth 2.0 PKCE-Authentifizierung: Erstmalige Anmeldung abschließen","description":"Lernen Sie den OAuth 2.0 PKCE-Authentifizierungsprozess kennen und schließen Sie die erstmalige Anmeldung für das Antigravity-Plugin ab. Beinhaltet Starten des lokalen OAuth-Servers, Google-Autorisierung, Abrufen der Project ID und Token-Speicherung.","tags":["OAuth","Authentifizierung","PKCE","Schnellstart"],"prerequisite":["start-quick-install"],"order":3},"headers":[],"relativePath":"de/NoeFabris/opencode-antigravity-auth/start/first-auth-login/index.md","filePath":"de/NoeFabris/opencode-antigravity-auth/start/first-auth-login/index.md"}'),a={name:"de/NoeFabris/opencode-antigravity-auth/start/first-auth-login/index.md"};function r(l,e,o,u,h,d){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="oauth-2-0-pkce-authentifizierung-erstmalige-anmeldung-abschließen" tabindex="-1">OAuth 2.0 PKCE-Authentifizierung: Erstmalige Anmeldung abschließen <a class="header-anchor" href="#oauth-2-0-pkce-authentifizierung-erstmalige-anmeldung-abschließen" aria-label="Permalink to &quot;OAuth 2.0 PKCE-Authentifizierung: Erstmalige Anmeldung abschließen&quot;">​</a></h1><h2 id="was-sie-nach-diesem-tutorial-konnen" tabindex="-1">Was Sie nach diesem Tutorial können <a class="header-anchor" href="#was-sie-nach-diesem-tutorial-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Tutorial können&quot;">​</a></h2><ul><li>Die Sicherheitsmechanismen des OAuth 2.0 PKCE-Authentifizierungsprozesses verstehen</li><li>Die erstmalige Anmeldung des Plugins abschließen und Zugriff auf die Antigravity-API erhalten</li><li>Den Mechanismus zum automatischen Abrufen und Speichern der Project ID verstehen</li><li>Die automatisierte Verarbeitung der Token-Aktualisierung kennenlernen</li></ul><h2 id="ihre-aktuelle-situation" tabindex="-1">Ihre aktuelle Situation <a class="header-anchor" href="#ihre-aktuelle-situation" aria-label="Permalink to &quot;Ihre aktuelle Situation&quot;">​</a></h2><p>Sie haben das Plugin installiert und die Modelldefinition konfiguriert, aber noch nicht wirklich verwendet. Jedes Mal, wenn Sie <code>opencode run</code> ausführen, erscheint die Meldung &quot;Authentifizierung erforderlich&quot;, aber Sie wissen nicht:</p><ul><li>Was ist OAuth? Warum wird ein so komplexer Authentifizierungsweg verwendet?</li><li>Was passiert während des Authentifizierungsprozesses? Ist es sicher?</li><li>Was muss für die erstmalige Anmeldung vorbereitet werden? Welche Optionen gibt es?</li><li>Was passiert, wenn der Token abläuft? Muss man sich erneut anmelden?</li></ul><h2 id="wann-diese-methode-verwenden" tabindex="-1">Wann diese Methode verwenden <a class="header-anchor" href="#wann-diese-methode-verwenden" aria-label="Permalink to &quot;Wann diese Methode verwenden&quot;">​</a></h2><ul><li><strong>Nach der ersten Installation</strong>: Die Authentifizierung muss vor der ersten Verwendung abgeschlossen werden</li><li><strong>Beim Hinzufügen neuer Konten</strong>: Bei der Konfiguration der Multi-Account-Rotation müssen Konten nacheinander authentifiziert werden</li><li><strong>Nach Token-Ablauf</strong>: Bei Widerruf des Kontos oder Änderung des Passworts muss eine erneute Authentifizierung erfolgen</li><li><strong>Beim Wechsel zu einem neuen Gerät</strong>: Bei der Migration von Konten ist eine erneute Anmeldung auf dem neuen Gerät erforderlich</li></ul><h2 id="🎒-vorbereitungen-vor-dem-start" tabindex="-1">🎒 Vorbereitungen vor dem Start <a class="header-anchor" href="#🎒-vorbereitungen-vor-dem-start" aria-label="Permalink to &quot;🎒 Vorbereitungen vor dem Start&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Voraussetzungen prüfen</p><p>Bitte bestätigen Sie, dass folgende Schritte abgeschlossen sind:</p><ol><li><strong>Plugin installiert</strong>: Siehe <a href="/docs/opencodedocs/de/NoeFabris/opencode-antigravity-auth/start/quick-install/">Schnellinstallation</a></li><li><strong>Modell konfiguriert</strong>: Die Modelldefinition wurde zu <code>~/.config/opencode/opencode.json</code> hinzugefügt</li><li><strong>Verfügbares Google-Konto</strong>: Es wird empfohlen, ein vertrauenswürdiges Konto zu verwenden und keine neu erstellten Konten zu nutzen</li></ol></div><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><h3 id="was-ist-oauth-2-0-pkce" tabindex="-1">Was ist OAuth 2.0 PKCE? <a class="header-anchor" href="#was-ist-oauth-2-0-pkce" aria-label="Permalink to &quot;Was ist OAuth 2.0 PKCE?&quot;">​</a></h3><p><strong>OAuth 2.0</strong> (Open Authorization 2.0) ist ein Autorisierungsprotokoll, das es Drittanbieteranwendungen (dieses Plugin) ermöglicht, Zugriff auf die Google-API zu erhalten, ohne direkt auf das Benutzerpasswort zuzugreifen.</p><p><strong>PKCE</strong> (Proof Key for Code Exchange) ist eine Sicherheitserweiterung für OAuth 2.0, die speziell für öffentliche Clients (wie CLI-Tools) entwickelt wurde. Sie verhindert Autorisierungscode-Abfangangriffe durch folgende Mechanismen:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  PKCE-Schutzmechanismus                                         │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  1. Client generiert ein Schlüsselpaar:                         │</span></span>
<span class="line"><span>│     - code_verifier (zufällige Zeichenkette, vertraulich)        │</span></span>
<span class="line"><span>│     - code_challenge (Hash des Verifiers, öffentlich)           │</span></span>
<span class="line"><span>│  2. Autorisierungs-URL enthält code_challenge                   │</span></span>
<span class="line"><span>│  3. Callback-Server erhält Code, verifiziert mit code_verifier  │</span></span>
<span class="line"><span>│  4. Angreifer, der den Code abfängt, kann ohne Verifier         │</span></span>
<span class="line"><span>│     keinen Token austauschen                                    │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p><strong>PKCE vs. traditionelles OAuth</strong></p><p>Traditionelles OAuth verwendet <code>client_secret</code> zur Identitätsverifizierung, aber dies erfordert, dass der Client den Schlüssel sicher speichern kann. CLI-Tools können dies nicht leisten, daher verwendet PKCE dynamisch generierte <code>verifier</code> anstelle statischer Schlüssel - gleich sicher, aber ohne Abhängigkeit von vorgespeicherten Geheimnissen.</p></div><h3 id="authentifizierungsprozess-uberblick" tabindex="-1">Authentifizierungsprozess-Überblick <a class="header-anchor" href="#authentifizierungsprozess-uberblick" aria-label="Permalink to &quot;Authentifizierungsprozess-Überblick&quot;">​</a></h3><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant U as Benutzer-Terminal</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant O as OAuth-Server</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant G as Google-Autorisierungsseite</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant A as Antigravity-API</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    U-&gt;&gt;O: 1. PKCE-Schlüsselpaar generieren</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    U-&gt;&gt;G: 2. Autorisierungs-URL öffnen (mit challenge)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G-&gt;&gt;O: 3. Benutzer autorisiert</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    O-&gt;&gt;U: 4. Callback-Code (localhost:51121)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    U-&gt;&gt;O: 5. Token austauschen (mit verifier)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    O-&gt;&gt;U: 6. access_token + refresh_token zurückgeben</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    U-&gt;&gt;A: 7. Project ID abrufen</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    U-&gt;&gt;U: 8. Kontoinformationen speichern</span></span></code></pre></div>`,18)])])}const g=n(a,[["render",r]]);export{p as __pageData,g as default};
